import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import styles from './Navbar.module.css'

const LOGO = 'data:image/jpeg;base64,'

export default function Navbar({ onAdmClick }) { // eslint-disable-line no-unused-vars
  const [menuOpen, setMenuOpen] = useState(false)
  const navigate = useNavigate()

  const scrollTo = (id) => {
    if (window.location.pathname === '/') {
      document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' })
    } else {
      navigate('/')
      setTimeout(() => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' }), 100)
    }
    setMenuOpen(false)
  }

  return (
    <nav className={styles.nav}>
      <Link to="/" className={styles.logoLink}>
        <img src={LOGO} alt="Felipe Mello Imóveis" className={styles.logoImg} />
      </Link>

      <div className={`${styles.links} ${menuOpen ? styles.open : ''}`}>
        <a onClick={() => scrollTo('imoveis')}>Imóveis</a>
        <a onClick={() => scrollTo('sobre')}>Sobre</a>
        <a onClick={() => scrollTo('contato')}>Contato</a>
        <a
          href="https://wa.me/5548999999999"
          target="_blank"
          rel="noopener noreferrer"
          className={styles.ctaBtn}
        >
          💬 WhatsApp
        </a>
      </div>

      <button className={styles.hamburger} onClick={() => setMenuOpen(!menuOpen)}>
        {menuOpen ? '✕' : '☰'}
      </button>
    </nav>
  )
}
